const isFinitePoint = (point) => point.every(Number.isFinite);

export const MATERIAL_DENSITY_G_CM3 = {
  PLA: 1.24,
  PETG: 1.27,
  ABS: 1.04,
  ASA: 1.07,
  TPU: 1.21,
  Resin: 1.15,
  Nylon: 1.14,
  'Carbon Fiber Reinforced': 1.30,
};

const INFILL_FACTORS = [
  [0, 0],
  [10, 0.30],
  [20, 0.40],
  [30, 0.50],
  [40, 0.60],
  [50, 0.70],
  [60, 0.80],
  [70, 0.90],
  [80, 0.95],
  [90, 0.98],
  [100, 1.00],
];

const DEFAULT_PRINTER_PROFILE = {
  name: 'Default FDM Profile',
  averagePrintSpeedMmS: 60,
  setupFactor: 1.15,
  efficiencyFactor: 0.85,
};

const MACHINE_COST_PER_MINUTE = 0.014;
const FIXED_COST = 9.86;
const MATERIAL_COST_PER_GRAM = 0.02751;

const roundOne = (value) => Math.round((Number(value) + Number.EPSILON) * 10) / 10;
const roundTwo = (value) => Math.round((Number(value) + Number.EPSILON) * 100) / 100;

const densityForMaterial = (materialPreference = '') => {
  const normalized = String(materialPreference || '').trim().toLowerCase();
  const key = Object.keys(MATERIAL_DENSITY_G_CM3).find(name => name.toLowerCase() === normalized);
  return key ? MATERIAL_DENSITY_G_CM3[key] : null;
};

const infillFactorFor = (infillPercentage) => {
  if (infillPercentage === null || infillPercentage === undefined || infillPercentage === '') return null;
  const infill = Number(infillPercentage);
  if (!Number.isFinite(infill) || infill < 0 || infill > 100) return null;
  for (let i = 0; i < INFILL_FACTORS.length - 1; i += 1) {
    const [lowInfill, lowFactor] = INFILL_FACTORS[i];
    const [highInfill, highFactor] = INFILL_FACTORS[i + 1];
    if (infill >= lowInfill && infill <= highInfill) {
      const ratio = (infill - lowInfill) / (highInfill - lowInfill);
      return lowFactor + ratio * (highFactor - lowFactor);
    }
  }
  return null;
};

export const calculateMaterialEstimates = ({ volumeMm3, materialPreference, infillPercentage }) => {
  const volume = Number(volumeMm3);
  const density = densityForMaterial(materialPreference);
  const infillFactor = infillFactorFor(infillPercentage);
  if (!Number.isFinite(volume) || volume <= 0 || density === null) {
    return {
      estimated_weight_g: null,
      estimated_material_usage_g: null,
      material_density_g_cm3: density,
      infill_factor: infillFactor,
    };
  }
  const estimatedWeight = roundOne((volume / 1000) * density);
  return {
    estimated_weight_g: estimatedWeight,
    estimated_material_usage_g: infillFactor === null ? null : roundOne(estimatedWeight * infillFactor),
    material_density_g_cm3: density,
    infill_factor: infillFactor,
  };
};

export const calculatePrintTimeEstimate = ({
  volumeMm3,
  estimatedMaterialUsageG,
  materialDensityGcm3,
  layerHeight,
  infillPercentage,
  printerProfile = DEFAULT_PRINTER_PROFILE,
}) => {
  const layer = Number(layerHeight);
  const density = Number(materialDensityGcm3);
  const usage = Number(estimatedMaterialUsageG);
  const volume = Number(volumeMm3);
  const infillFactor = infillFactorFor(infillPercentage);
  if (!Number.isFinite(layer) || layer <= 0) {
    return { estimated_print_time_minutes: null, estimated_print_time_hours: null, printer_profile_name: null };
  }
  const effectiveVolumeMm3 = Number.isFinite(usage) && usage > 0 && Number.isFinite(density) && density > 0
    ? (usage / density) * 1000
    : (Number.isFinite(volume) && volume > 0 && infillFactor !== null ? volume * infillFactor : null);
  if (!effectiveVolumeMm3 || effectiveVolumeMm3 <= 0) {
    return { estimated_print_time_minutes: null, estimated_print_time_hours: null, printer_profile_name: null };
  }
  const speed = Number(printerProfile.averagePrintSpeedMmS || DEFAULT_PRINTER_PROFILE.averagePrintSpeedMmS);
  const setup = Number(printerProfile.setupFactor || DEFAULT_PRINTER_PROFILE.setupFactor);
  const efficiency = Number(printerProfile.efficiencyFactor || DEFAULT_PRINTER_PROFILE.efficiencyFactor);
  const volumetricRateMm3S = 0.45 * layer * speed * efficiency;
  if (!Number.isFinite(volumetricRateMm3S) || volumetricRateMm3S <= 0) {
    return { estimated_print_time_minutes: null, estimated_print_time_hours: null, printer_profile_name: printerProfile.name };
  }
  const minutes = (effectiveVolumeMm3 / volumetricRateMm3S / 60) * setup;
  return {
    estimated_print_time_minutes: roundOne(minutes),
    estimated_print_time_hours: roundTwo(minutes / 60),
    printer_profile_name: printerProfile.name || DEFAULT_PRINTER_PROFILE.name,
  };
};

export const calculateStlCostEstimate = ({
  estimatedMaterialUsageG,
  estimatedPrintTimeMinutes,
  variableCostPerG = MATERIAL_COST_PER_GRAM,
}) => {
  const usage = Number(estimatedMaterialUsageG);
  const minutes = Number(estimatedPrintTimeMinutes);
  const materialRate = Number(variableCostPerG || MATERIAL_COST_PER_GRAM);
  if (!Number.isFinite(usage) || usage <= 0 || !Number.isFinite(minutes) || minutes <= 0) {
    return {
      stl_material_cost: null,
      stl_time_cost: null,
      stl_fixed_cost: null,
      stl_estimated_total_cost: null,
      stl_variable_cost_per_g: materialRate,
      stl_machine_cost_per_minute: MACHINE_COST_PER_MINUTE,
    };
  }
  const materialCost = roundTwo(usage * materialRate);
  const timeCost = roundTwo(minutes * MACHINE_COST_PER_MINUTE);
  return {
    stl_material_cost: materialCost,
    stl_time_cost: timeCost,
    stl_fixed_cost: FIXED_COST,
    stl_estimated_total_cost: roundTwo(materialCost + timeCost + FIXED_COST),
    stl_variable_cost_per_g: materialRate,
    stl_machine_cost_per_minute: MACHINE_COST_PER_MINUTE,
  };
};

export const withMaterialEstimates = (metadata, materialPreference, infillPercentage, layerHeight) => {
  if (!metadata || metadata.parse_status === 'invalid') return metadata;
  const materialEstimates = calculateMaterialEstimates({
    volumeMm3: metadata.volume_mm3,
    materialPreference,
    infillPercentage,
  });
  return {
    ...metadata,
    ...materialEstimates,
    ...(() => {
      const printTime = calculatePrintTimeEstimate({
        volumeMm3: metadata.volume_mm3,
        estimatedMaterialUsageG: materialEstimates.estimated_material_usage_g,
        materialDensityGcm3: materialEstimates.material_density_g_cm3,
        layerHeight,
        infillPercentage,
      });
      return {
        ...printTime,
        ...calculateStlCostEstimate({
          estimatedMaterialUsageG: materialEstimates.estimated_material_usage_g,
          estimatedPrintTimeMinutes: printTime.estimated_print_time_minutes,
        }),
      };
    })(),
  };
};

const emptyState = () => ({
  triangleCount: 0,
  signedVolume: 0,
  minX: Infinity,
  minY: Infinity,
  minZ: Infinity,
  maxX: -Infinity,
  maxY: -Infinity,
  maxZ: -Infinity,
});

const addTriangle = (state, a, b, c) => {
  if (!isFinitePoint(a) || !isFinitePoint(b) || !isFinitePoint(c)) return;
  [a, b, c].forEach(([x, y, z]) => {
    state.minX = Math.min(state.minX, x);
    state.minY = Math.min(state.minY, y);
    state.minZ = Math.min(state.minZ, z);
    state.maxX = Math.max(state.maxX, x);
    state.maxY = Math.max(state.maxY, y);
    state.maxZ = Math.max(state.maxZ, z);
  });
  const crossX = b[1] * c[2] - b[2] * c[1];
  const crossY = b[2] * c[0] - b[0] * c[2];
  const crossZ = b[0] * c[1] - b[1] * c[0];
  state.signedVolume += (a[0] * crossX + a[1] * crossY + a[2] * crossZ) / 6;
  state.triangleCount += 1;
};

const finish = (state) => {
  if (!state.triangleCount || !Number.isFinite(state.minX)) {
    throw new Error('No triangles found in STL file');
  }
  return {
    parse_status: 'valid',
    triangle_count: state.triangleCount,
    volume_mm3: Math.abs(state.signedVolume),
    bounding_box_x_mm: state.maxX - state.minX,
    bounding_box_y_mm: state.maxY - state.minY,
    bounding_box_z_mm: state.maxZ - state.minZ,
    units: 'mm',
  };
};

const parseBinaryStl = (dataView, byteLength) => {
  if (byteLength < 84) throw new Error('Binary STL is too small');
  const triangleCount = dataView.getUint32(80, true);
  const expectedLength = 84 + triangleCount * 50;
  if (expectedLength > byteLength) throw new Error('Binary STL is truncated');

  const state = emptyState();
  for (let offset = 84; offset + 49 < expectedLength; offset += 50) {
    const a = [dataView.getFloat32(offset + 12, true), dataView.getFloat32(offset + 16, true), dataView.getFloat32(offset + 20, true)];
    const b = [dataView.getFloat32(offset + 24, true), dataView.getFloat32(offset + 28, true), dataView.getFloat32(offset + 32, true)];
    const c = [dataView.getFloat32(offset + 36, true), dataView.getFloat32(offset + 40, true), dataView.getFloat32(offset + 44, true)];
    addTriangle(state, a, b, c);
  }
  return finish(state);
};

const parseAsciiStl = (arrayBuffer) => {
  const text = new TextDecoder('utf-8').decode(arrayBuffer);
  const vertexRe = /vertex\s+([+-]?(?:\d+(?:\.\d*)?|\.\d+)(?:e[+-]?\d+)?)\s+([+-]?(?:\d+(?:\.\d*)?|\.\d+)(?:e[+-]?\d+)?)\s+([+-]?(?:\d+(?:\.\d*)?|\.\d+)(?:e[+-]?\d+)?)/gi;
  const vertices = [];
  let match;
  while ((match = vertexRe.exec(text))) {
    vertices.push([Number(match[1]), Number(match[2]), Number(match[3])]);
  }
  if (vertices.length < 3 || vertices.length % 3 !== 0) throw new Error('ASCII STL vertex data is invalid');

  const state = emptyState();
  for (let i = 0; i < vertices.length; i += 3) {
    addTriangle(state, vertices[i], vertices[i + 1], vertices[i + 2]);
  }
  return finish(state);
};

export const parseStlFile = async (file) => {
  const arrayBuffer = await file.arrayBuffer();
  await new Promise(resolve => setTimeout(resolve, 0));

  const byteLength = arrayBuffer.byteLength;
  const dataView = new DataView(arrayBuffer);
  const header = new TextDecoder('utf-8').decode(arrayBuffer.slice(0, Math.min(80, byteLength))).trim().toLowerCase();
  const looksBinary = byteLength >= 84 && 84 + dataView.getUint32(80, true) * 50 <= byteLength;

  try {
    if (looksBinary && !header.startsWith('solid')) return parseBinaryStl(dataView, byteLength);
    return parseAsciiStl(arrayBuffer);
  } catch (asciiError) {
    if (looksBinary) return parseBinaryStl(dataView, byteLength);
    throw asciiError;
  }
};

export const invalidStlMetadata = (message = 'Invalid STL File') => ({
  parse_status: 'invalid',
  error_message: message,
  volume_mm3: null,
  bounding_box_x_mm: null,
  bounding_box_y_mm: null,
  bounding_box_z_mm: null,
  triangle_count: null,
  estimated_weight_g: null,
  estimated_material_usage_g: null,
  material_density_g_cm3: null,
  infill_factor: null,
  estimated_print_time_minutes: null,
  estimated_print_time_hours: null,
  printer_profile_name: null,
  stl_material_cost: null,
  stl_time_cost: null,
  stl_fixed_cost: null,
  stl_estimated_total_cost: null,
  stl_variable_cost_per_g: null,
  stl_machine_cost_per_minute: null,
  units: 'mm',
